local AdminIds = { "80" }

local function isGMOpen(userId)
    if isTest then
        return true
    end
    return TableUtil.include(AdminIds, tostring(userId))
end

local function init()
    CommonDataEvents:registerCallBack("GMCommand", function(userId, data)
        if not isGMOpen(userId) then
            return
        end
        local player = PlayerManager:getPlayerByUserId(userId)
        if not player then
            player = PlayerManager:getWatcherByUserId(userId)
            if not player then
                return
            end
        end
        GMHelper:callCommand(player, data.name, unpack(data.params))
    end, JsonBuilderProcessor)
end

local function findLifeOtherPlayer(player)
    local players = PlayerManager:getPlayers()
    local lifeCount = 0
    for _, _player in pairs(players) do
        if not _player:isDead() then
            lifeCount = lifeCount + 1
        end
    end
    if lifeCount < 2 then
        return
    end
    local random
    if player:isDead() then
        random = math.random(1, lifeCount)
    else
        random = math.random(1, lifeCount - 1)
    end
    local current = 0
    for _, _player in pairs(players) do
        if _player ~= player and not _player:isDead() then
            current = current + 1
        end
        if current == random then
            return _player
        end
    end
end

